part of '../app_router.dart';

Future<void> _handleDriverProfileSetupSave(
  BuildContext context, {
  required String name,
  required String phone,
  required String plate,
  required bool showPhoneToPassengers,
  String? photoUrl,
  String? photoPath,
}) async {
  try {
    await _upsertDriverProfileUseCase.execute(
      DriverProfileUpsertCommand(
        name: name,
        phone: phone,
        plate: plate.toUpperCase(),
        showPhoneToPassengers: showPhoneToPassengers,
        photoUrl: photoUrl,
        photoPath: photoPath,
        companyId: null,
      ),
    );

    final user = _authCredentialGateway.currentUser;
    if (user != null) {
      try {
        await _driverPushTokenRegistrationService.registerForUid(user.uid);
      } catch (_) {
        // Driver profile kaydedildi; device register kritik olmayan fallback.
      }
    }

    if (!context.mounted) {
      return;
    }
    _showInfo(context,
