Future<void> _handleDeleteAccount(
  BuildContext context, {
  required AppEnvironment environment,
}) async {
  try {
    final result = await _deleteUserDataUseCase.execute(
      const DeleteUserDataCommand(dryRun: false),
    );
    if (!context.mounted) {
      return;
    }
    final resultPlan = _planDeleteAccountResultHandlingUseCase.execute(
      PlanDeleteAccountResultHandlingCommand(
        status: result.status,
        interceptorMessage: result.interceptorMessage,
        manageSubscriptionLabel: result.manageSubscriptionLabel,
        defaultBlockedSubscriptionMessage: PaywallCopyTr.deleteInterceptorBody,
        defaultManageSubscriptionLabel:
            PaywallCopyTr.deleteInterceptorCtaManage,
        successMessage: 'Hesap silme talebi alindi.',
      ),
    );
    if (resultPlan.action ==
        DeleteAccountResultHandlingAction.showBlockedSubscriptionDialog) {
      final manageUri = _resolveDeleteInterceptorManageUri(
        payload: <String, dynamic>{
          if (result.manageSubscriptionUrls != null)
            'manageSubscriptionUrls': result.manageSubscriptionUrls,
        },
        environment: environment,
      );
      final openManage = await showDialog<bool>(
        context: context,
        builder: (dialogContext) {
          return AlertDialog(
            title: const Text(PaywallCopyTr.deleteInterceptorTitle),
            content: Text(resultPlan.feedbackMessage),
            actions: <Widget>[
              TextButton(
                onPressed: () => Navigator.of(dialogContext).pop(false),
                child: const Text(PaywallCopyTr.deleteInterceptorCtaCancel),
              ),
              TextButton(
                onPressed: () => Navigator.of(dialogContext).pop(true),
                child: Text(resultPlan.manageSubscriptionLabel ?? ''),
              ),
            ],
          );
        },
      );
      if (openManage == true) {
        final opened = await _tryOpenExternalUri(manageUri);
        if (context.mounted && !opened) {
