  } catch (_) {
    if (!context.mounted) {
      return;
    }
    final failurePlan = _planProfileUpdateFeedbackHandlingUseCase.execute(
      const PlanProfileUpdateFeedbackHandlingCommand(
        succeeded: false,
        successMessage: '',
      ),
    );
    _showInfo(context, failurePlan.feedbackMessage);
    if (failurePlan.action ==
        ProfileUpdateFeedbackHandlingAction.showInfoAndRethrow) {
      rethrow;
    }
  }
}

Future<({String photoUrl, String photoPath})?> _handleProfilePhotoPick(
  BuildContext context, {
  required UserRole role,
  String? currentPhotoPath,
}) async {
  final user = _authCredentialGateway.currentUser;
  if (user == null || user.isAnonymous) {
    if (context.mounted) {
      _showInfo(
        context,
        _resolveAccountProfileOperationFeedbackMessageUseCase.execute(
          AccountProfileOperationFeedbackKind.sessionMissingSignInAgain,
        ),
      );
    }
    return null;
  }

  try {
    final upload = await _profilePhotoUploadService.pickCompressAndUpload(
      uid: user.uid,
      role: role.name,
      previousPhotoPath: currentPhotoPath,
    );
    if (upload == null) {
      return null;
    }
    try {
      await user.updatePhotoURL(upload.downloadUrl);
    } catch (_) {
      // Non-critical: auth photoUrl can lag behind profile documents.
    }
    if (context.mounted) {
      _showInfo(
        context,
        _resolveAccountProfileOperationFeedbackMessageUseCase.execute(
          AccountProfileOperationFeedbackKind.profilePhotoUploadSucceeded,
        ),
      );
    }
    return (
      photoUrl: upload.downloadUrl,
      photoPath: upload.storagePath,
    );
  } catch (_) {
    if (context.mounted) {
      _showInfo(
        context,
        _resolveAccountProfileOperationFeedbackMessageUseCase.execute(
          AccountProfileOperationFeedbackKind.profilePhotoUploadFailed,
        ),
      );
    }
    return null;
  }
}
